# logo en base64, va todo junto acá
_LOGO_B64 = """"""

_ICON_B64 = """"""

def _build_logo_photo(size):
    """
    Compone el logo sobre fondo oscuro y lo guarda en un .ppm temporal.
    Devuelve tk.PhotoImage cargado desde archivo — único método confiable en Windows.
    """
    try:
        from PIL import Image as PILImage
        import base64, io, tempfile, os, tkinter as tk
        raw  = base64.b64decode(_LOGO_B64)
        img  = PILImage.open(io.BytesIO(raw)).convert("RGBA")
        img  = img.resize((size, size), PILImage.LANCZOS)
        # le bajo la opacidad a 20% que si no tapa todo
        r, g, b, a = img.split()
        a2 = a.point(lambda x: int(x * 0.20))
        img.putalpha(a2)
        # lo compongo sobre el fondo del panel para que no se vea el cuadrado
        bg = PILImage.new("RGBA", (size, size), (19, 22, 30, 255))
        bg.paste(img, (0, 0), img)
        rgb = bg.convert("RGB")
        # PPM porque PhotoImage en Windows no traga PNG bien
        tmp = tempfile.NamedTemporaryFile(suffix=".ppm", delete=False)
        rgb.save(tmp, format="PPM")
        tmp.close()
        # ojo: tiene que ser file=, con data= no anda en Windows
        photo = tk.PhotoImage(file=tmp.name)
        os.unlink(tmp.name)
        return photo
    except Exception:
        return None

CURVE_TYPES = ["Lineal", "Exponencial", "Logarítmica", "S-Curve", "Personalizada"]

PEDALES = [
    {"key": "embrague",   "label": "Embrague",    "color": ACCENT3, "axis": 2},  # Brake → pedal embrague
    {"key": "freno",      "label": "Freno",       "color": ACCENT2, "axis": 1},  # Throttle → pedal freno
    {"key": "acelerador", "label": "Acelerador", "color": ACCENT,  "axis": 0},  # RyAxis → pedal acelerador
]


def apply_curve(raw, curve_type, raw_min, raw_max, control_points=None):
    span = raw_max - raw_min
    if span == 0:
        return 0.0
    t = max(0.0, min(1.0, (raw - raw_min) / span))
    if curve_type == "Exponencial":
        return t ** 2
    elif curve_type == "Logarítmica":
        return math.log1p(t * (math.e - 1))
    elif curve_type == "S-Curve":
        return t * t * (3 - 2 * t)
    elif curve_type == "Personalizada" and control_points:
        pts = [(0.0, 0.0)] + list(control_points) + [(1.0, 1.0)]
        xs = [p[0] for p in pts]
        ys = [p[1] for p in pts]
        for i in range(len(xs) - 1):
            if xs[i] <= t <= xs[i+1]:
                if xs[i+1] == xs[i]:
                    return float(ys[i])
                frac = (t - xs[i]) / (xs[i+1] - xs[i])
                return float(ys[i] + frac * (ys[i+1] - ys[i]))
        return t
    return t


# ── Calibración persistente de Windows (DirectInput) ──────────────────────
# Escribe MIN/MAX/CENTRO en el registro para que la calibración quede fija
# a nivel sistema, para cualquier juego, aunque el calibrador esté cerrado.
# OJO: esto NO puede guardar la curva de respuesta ni el deadzone — eso
# sigue viviendo solo dentro de esta app. Windows solo entiende un mapeo
# lineal (Min/Centro/Max) por eje.

BACKUP_DIR = os.path.join(os.path.expanduser("~"), ".vr_calibrador_backups")


def _guid_to_vid_pid(guid_hex):
    """Extrae VID/PID del GUID que entrega pygame/SDL para el joystick.
    Formato típico en Windows: [bus(2)][crc(2)][vendor(2)][0(2)][product(2)][0(2)][version(2)][0(2)]
    Si el device no sigue este layout puede no dar un VID/PID válido —
    por eso siempre se puede pisar a mano en la UI."""
    try:
        raw = bytes.fromhex(guid_hex)
        vendor  = struct.unpack("<H", raw[4:6])[0]
        product = struct.unpack("<H", raw[8:10])[0]
        return vendor, product
    except Exception:
        return None, None


def _calibration_key_path(vid, pid, axis_index):
    return (
        r"System\CurrentControlSet\Control\MediaProperties\PrivateProperties"
        rf"\DirectInput\VID_{vid:04X}&PID_{pid:04X}\Calibration\0\Type\Axes\{axis_index}"
    )


def read_windows_calibration(vid, pid, axis_index):
    """Devuelve (lMin, lCenter, lMax) actuales, o None si no hay nada guardado."""
    if not WINREG_OK:
        return None
    path = _calibration_key_path(vid, pid, axis_index)
    try:
        key = winreg.OpenKey(winreg.HKEY_CURRENT_USER, path, 0, winreg.KEY_READ)
        data, _ = winreg.QueryValueEx(key, "Calibration")
        winreg.CloseKey(key)
        if len(data) >= 12:
            return struct.unpack("<iii", data[:12])
    except FileNotFoundError:
        return None
    except Exception:
        return None
    return None


def backup_windows_calibration(vid, pid, axis_index, axis_label):
    """Guarda la calibración actual (si existe) en un json local, antes de pisarla."""
    current = read_windows_calibration(vid, pid, axis_index)
    if current is None:
        return None  # no había nada que respaldar
    os.makedirs(BACKUP_DIR, exist_ok=True)
    ts = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    fname = f"backup_VID{vid:04X}_PID{pid:04X}_axis{axis_index}_{ts}.json"
    fpath = os.path.join(BACKUP_DIR, fname)
    with open(fpath, "w", encoding="utf-8") as f:
        json.dump({
            "vid": vid, "pid": pid, "axis_index": axis_index,
            "axis_label": axis_label,
            "lMin": current[0], "lCenter": current[1], "lMax": current[2],
            "timestamp": ts,
        }, f, indent=2)
    return fpath


def write_windows_calibration(vid, pid, axis_index, raw_min, raw_center, raw_max):
    """Escribe lMin/lCenter/lMax para el eje indicado. Requiere Windows."""
    if not WINREG_OK:
        raise RuntimeError("winreg no disponible: esta función solo corre en Windows.")
    path = _calibration_key_path(vid, pid, axis_index)
    key = winreg.CreateKeyEx(winreg.HKEY_CURRENT_USER, path, 0, winreg.KEY_SET_VALUE)
    data = struct.pack("<iii", raw_min, raw_center, raw_max)
    winreg.SetValueEx(key, "Calibration", 0, winreg.REG_BINARY, data)
    winreg.CloseKey(key)


def restore_windows_calibration(backup_path):
    """Restaura una calibración desde un archivo de backup generado antes."""
    with open(backup_path, encoding="utf-8") as f:
        b = json.load(f)
    write_windows_calibration(b["vid"], b["pid"], b["axis_index"],
                               b["lMin"], b["lCenter"], b["lMax"])


def _set_window_icon(window):
    """Setea el ícono de la ventana desde el ICO embebido."""
    try:
        from PIL import Image as PILImage
        import base64, io, tempfile, os, tkinter as tk
        raw = base64.b64decode(_ICON_B64)
        tmp = tempfile.NamedTemporaryFile(suffix=".ico", delete=False)
        tmp.write(raw)
        tmp.close()
        window.iconbitmap(tmp.name)
        os.unlink(tmp.name)
    except Exception:
        pass

def _build_header_logo():
    """Devuelve CTkImage del logo para el header (40x40)."""
    try:
        from PIL import Image as PILImage
        import base64, io
        raw = base64.b64decode(_LOGO_B64)
        img = PILImage.open(io.BytesIO(raw)).convert("RGBA")
        # el png viene con transparencia, lo relleno con el color del panel
        bg = PILImage.new("RGBA", img.size, (19, 22, 30, 255))
        bg.paste(img, (0, 0), img)
        rgb = bg.convert("RGB").resize((40, 40), PILImage.LANCZOS)
        return ctk.CTkImage(light_image=rgb, dark_image=rgb, size=(40, 40))
    except Exception:
        return None


class PedalCanvas(ctk.CTkCanvas):
    def __init__(self, master, label, color, **kwargs):
        super().__init__(master, bg=PANEL, highlightthickness=0, **kwargs)
        self.label = label
        self.color = color
        self.raw_value = 0
        self.out_value = 0.0
        self.bind("<Configure>", self._redraw)

    def update_values(self, raw, out):
        self.raw_value = raw
        self.out_value = out
        self._redraw()

    def _redraw(self, event=None):
        self.delete("all")
        w = self.winfo_width()
        h = self.winfo_height()
        if w < 10 or h < 10:
            return
        pad = 16
        bar_w = 28
        bar_x = w // 2 - bar_w // 2
        bar_top = pad + 24
        bar_bot = h - pad - 46
        bar_h = bar_bot - bar_top
        fill_h = int(bar_h * self.out_value)

        self.create_rectangle(bar_x, bar_top, bar_x + bar_w, bar_bot,
                               fill="#1a1e2a", outline=BORDER, width=1)
        if fill_h > 0:
            steps = min(fill_h, 40)
            for i in range(steps):
                frac = i / steps
                c = self._lerp(self.color, frac)
                y1 = bar_bot - int(fill_h * (i + 1) / steps)
                y2 = bar_bot - int(fill_h * i / steps)
                if y2 > y1:
                    self.create_rectangle(bar_x+1, y1, bar_x+bar_w-1, y2, fill=c, outline="")
        if fill_h > 2:
            self.create_rectangle(bar_x+1, bar_bot-fill_h,
                                   bar_x+bar_w-1, bar_bot-fill_h+2,
                                   fill=self.color, outline="")
        self.create_text(w//2, pad+8, text=self.label.upper(),
                         fill=self.color, font=("Segoe UI", 8, "bold"), anchor="center")
        pct = int(self.out_value * 100)
        self.create_text(w//2, bar_bot+14, text=f"{pct}%",
                         fill=TEXT, font=("Segoe UI", 13, "bold"), anchor="center")
        self.create_text(w//2, bar_bot+30, text=f"raw {self.raw_value}",
                         fill=TEXT_DIM, font=FONT_MONO, anchor="center")

    def _lerp(self, color, t):
        r1,g1,b1 = 26,30,42
        r2,g2,b2 = int(color[1:3],16), int(color[3:5],16), int(color[5:7],16)
        return f"#{int(r1+(r2-r1)*t):02x}{int(g1+(g2-g1)*t):02x}{int(b1+(b2-b1)*t):02x}"


class CurveCanvas(ctk.CTkCanvas):
    _logo_cache = {}

    def __init__(self, master, **kwargs):
        super().__init__(master, bg=PANEL, highlightthickness=0, **kwargs)
        self.curve_type = "Lineal"
        self.live_pos   = 0.0
        self._logo_ref  = None
        self.control_points = [(0.25, 0.20), (0.50, 0.50), (0.75, 0.80)]
        self._dragging  = None
        self._disabled = False
        self.on_points_changed = None  # callback opcional: se llama cuando cambian los puntos
        self.bind("<Configure>",       self._redraw)
        self.bind("<Button-1>",        self._on_click)
        self.bind("<B1-Motion>",       self._on_drag)
        self.bind("<ButtonRelease-1>", self._on_release)
        self.bind("<Motion>",          self._on_hover)

    @classmethod
    def get_logo(cls, w, h):
        key = (w, h)
        if key not in cls._logo_cache:
            cls._logo_cache[key] = _build_logo_photo(min(w, h))
        return cls._logo_cache[key]

    # ─── Coordenadas ─────────────────────────────────────────────────────────
    def _pad(self): return 16

    def _to_canvas(self, x, y):
        w, h, p = self.winfo_width(), self.winfo_height(), self._pad()
        return p + x * (w - 2*p), p + (1 - y) * (h - 2*p)

    def _to_norm(self, cx, cy):
        w, h, p = self.winfo_width(), self.winfo_height(), self._pad()
        iw, ih = w - 2*p, h - 2*p
        return (cx - p) / iw if iw else 0, 1.0 - (cy - p) / ih if ih else 0

    def _hit(self, ex, ey, r=10):
        for i, (px, py) in enumerate(self.control_points):
            cx, cy = self._to_canvas(px, py)
            if abs(ex - cx) <= r and abs(ey - cy) <= r:
                return i
        return None

    # ─── Mouse ───────────────────────────────────────────────────────────────
    def _on_hover(self, event):
        if self.curve_type == "Personalizada":
            self.configure(cursor="fleur" if self._hit(event.x, event.y) is not None else "")

    def _on_click(self, event):
        if self.curve_type == "Personalizada":
            self._dragging = self._hit(event.x, event.y)

    def _on_drag(self, event):
        if self._dragging is None:
            return
        x, y = self._to_norm(event.x, event.y)
        x, y = max(0.0, min(1.0, x)), max(0.0, min(1.0, y))
        pts, m = self.control_points, 0.08
        if self._dragging == 0:
            x = max(m, min(x, pts[1][0] - m))
        elif self._dragging == 1:
            x = max(pts[0][0] + m, min(x, pts[2][0] - m))
        else:
            x = max(pts[1][0] + m, min(x, 1.0 - m))
        self.control_points[self._dragging] = (x, y)
        self._redraw()
        if self.on_points_changed:
            self.on_points_changed()

    def _on_release(self, event):
        self._dragging = None

    def get_points(self):
        return [list(p) for p in self.control_points]

    def set_points(self, pts):
        self.control_points = [(p[0], p[1]) for p in pts]
        self._redraw()
        if self.on_points_changed:
            self.on_points_changed()

    # ─── Público ─────────────────────────────────────────────────────────────
    def set_disabled(self, disabled: bool):
        self._disabled = disabled
        self._redraw()

    def set_curve(self, v):
        self.curve_type = v
        self._redraw()

    def set_live(self, pos):
        self.live_pos = pos
        self._redraw()

    def _redraw(self, event=None):
        self.delete("all")
        w = self.winfo_width()
        h = self.winfo_height()
        if w < 20 or h < 20:
            return

        self._logo_ref = CurveCanvas.get_logo(w, h)
        if self._logo_ref:
            self.create_image(w // 2, h // 2, image=self._logo_ref, anchor="center")

        pad = self._pad()
        iw, ih = w - 2*pad, h - 2*pad

        # la grilla de fondo
        for i in range(5):
            x = pad + i * iw // 4
            y = pad + i * ih // 4
            self.create_line(x, pad, x, pad+ih, fill=BORDER, dash=(2,4))
            self.create_line(pad, y, pad+iw, y, fill=BORDER, dash=(2,4))
        self.create_line(pad, pad+ih, pad+iw, pad+ih, fill=TEXT_DIM, width=1)
        self.create_line(pad, pad, pad, pad+ih, fill=TEXT_DIM, width=1)

        # dibujo la curva posta
        cp = self.control_points if self.curve_type == "Personalizada" else None
        pts = []
        for i in range(81):
            t = i / 80
            out = apply_curve(t, self.curve_type, 0, 1, cp)
            pts.extend([pad + int(t * iw), pad + ih - int(out * ih)])
        if len(pts) >= 4:
            self.create_line(*pts, fill=ACCENT, width=2, smooth=True)

        # los puntitos que se arrastran, solo si es curva Personalizada
        if self.curve_type == "Personalizada":
            for i, (px, py) in enumerate(self.control_points):
                cx, cy = self._to_canvas(px, py)
                col = "#ffffff" if self._dragging == i else ACCENT
                self.create_oval(cx-7, cy-7, cx+7, cy+7,
                                 fill=col, outline=PANEL, width=2)
                # las lineas punteadas de guia
                self.create_line(cx, cy, cx, pad+ih, fill=BORDER, dash=(3,5))
                self.create_line(pad, cy, cx, cy,   fill=BORDER, dash=(3,5))

        # el puntito que se mueve en vivo con el pedal
        out_live = apply_curve(self.live_pos, self.curve_type, 0, 1, cp)
        lx = pad + int(self.live_pos * iw)
        ly = pad + ih - int(out_live * ih)
        self.create_oval(lx-5, ly-5, lx+5, ly+5, fill=ACCENT, outline="")

        # tapo todo con "SIN EJE" si no hay eje mapeado
        if getattr(self, "_disabled", False):
            self.create_rectangle(0, 0, w, h, fill="#0d0f14", stipple="gray50", outline="")
            self.create_text(w//2, h//2, text="SIN EJE", fill=TEXT_DIM,
                             font=("Courier New", 12, "bold"), anchor="center")


class AxisPanel(ctk.CTkFrame):
    def __init__(self, master, label, color, axis_key, app, **kwargs):
        super().__init__(master, fg_color=PANEL, corner_radius=8, **kwargs)
        self.label     = label
        self.color     = color
        self.axis_key  = axis_key
        self.app       = app

        self.var_min     = ctk.StringVar(value="0")
        self.var_max     = ctk.StringVar(value="65535")
        self.var_dz_low  = ctk.StringVar(value="0")
        self.var_dz_high = ctk.StringVar(value="0")
        self.curve_var   = ctk.StringVar(value="Lineal")
        self.var_invert  = ctk.BooleanVar(value=False)
        # sugerido = mismo indice que usa pygame, pero HAY QUE CONFIRMARLO a mano
        # (pygame y DirectInput no siempre numeran los ejes igual)
        _hint = next((p["axis"] for p in PEDALES if p["key"] == axis_key), 0)
        self.var_di_axis = ctk.StringVar(value=str(_hint))
        self._win_cal    = None  # (lo, ce, hi) cacheado del registro, o None

        self._build()

    def _raw_corrected(self, raw):
        """Corrige el sentido del eje si el pedal reporta la medición invertida."""
        return (65535 - raw) if self.var_invert.get() else raw

    def _build(self):
        ctk.CTkLabel(self, text=self.label.upper(),
                     font=("Segoe UI", 12, "bold"),
                     text_color=self.color).pack(pady=(10,2))

        top = ctk.CTkFrame(self, fg_color="transparent")
        top.pack(fill="both", expand=True, padx=8)

        self.bar = PedalCanvas(top, "Lectura", "#6b7280", width=70, height=180)
        self.bar.pack(side="left", fill="y", padx=(0,4))

        self.bar_win = PedalCanvas(top, self.label, self.color, width=70, height=180)
        self.bar_win.pack(side="left", fill="y", padx=(0,6))

        self.curve = CurveCanvas(top, width=140, height=180)
        self.curve.pack(side="left", fill="both", expand=True)

        ctrl = ctk.CTkFrame(self, fg_color="transparent")
        ctrl.pack(fill="x", padx=8, pady=4)

        for lbl, var in [("MIN", self.var_min), ("MAX", self.var_max)]:
            row = ctk.CTkFrame(ctrl, fg_color="transparent")
            row.pack(fill="x", pady=1)
            ctk.CTkLabel(row, text=lbl, width=36, font=FONT_MONO,
                         text_color=TEXT_DIM).pack(side="left")
            ctk.CTkEntry(row, textvariable=var, width=72,
                          font=FONT_MONO, fg_color=BG,
                          border_color=BORDER).pack(side="left", padx=3)
            ctk.CTkButton(row, text=f"⊙ Capturar {lbl}",
                           width=100, height=24,
                           fg_color=BORDER, hover_color="#2a2f3d",
                           text_color=self.color, font=("Segoe UI", 9),
                           command=lambda v=var: v.set(str(self._raw_corrected(self.app.get_raw(self.axis_key))))
                           ).pack(side="left")

        cr = ctk.CTkFrame(ctrl, fg_color="transparent")
        cr.pack(fill="x", pady=3)
        ctk.CTkLabel(cr, text="Curva", width=55, font=FONT_MONO,
                     text_color=TEXT_DIM).pack(side="left")
        ctk.CTkOptionMenu(cr, values=CURVE_TYPES, variable=self.curve_var,
                           fg_color=BORDER, button_color="#2a2f3d",
                           button_hover_color=ACCENT, dropdown_fg_color=PANEL,
                           font=FONT_UI, width=130,
                           command=lambda v: self.curve.set_curve(v)
                           ).pack(side="left", padx=3)

        # (los puntos de la curva "Personalizada" se ajustan arrastrando en el gráfico)

        inv = ctk.CTkFrame(ctrl, fg_color="transparent")
        inv.pack(fill="x", pady=(3,0))
        ctk.CTkCheckBox(inv, text="Invertir pedal",
                          variable=self.var_invert,
                          onvalue=True, offvalue=False,
                          font=FONT_UI, text_color=TEXT_DIM,
                          fg_color=self.color, hover_color=self.color,
                          border_color=BORDER, checkbox_width=18,
                          checkbox_height=18).pack(side="left")

        # ── Calibración fija de Windows ──
        winbtn = ctk.CTkFrame(ctrl, fg_color="transparent")
        winbtn.pack(fill="x", pady=(3,0))
        self.btn_aplicar = ctk.CTkButton(winbtn, text="Aplicar a este pedal",
                       height=26, fg_color=BORDER, hover_color="#2a2f3d",
                       text_color=self.color, font=("Segoe UI", 9, "bold"),
                       command=self._aplicar_calibracion_windows)
        self.btn_aplicar.pack(side="left", fill="x", expand=True)

        self.lbl_win_status = ctk.CTkLabel(ctrl, text="Registro Windows: (sin consultar)",
                       font=("Segoe UI", 9), text_color=TEXT_DIM, anchor="w")
        self.lbl_win_status.pack(fill="x", pady=(2,0))
        self.after(300, self._refrescar_estado_windows)

        # si el usuario retoca MIN/MAX/Centro despues de aplicar, reactivo el boton
        for v in (self.var_min, self.var_max):
            v.trace_add("write", lambda *_: self.btn_aplicar.configure(state="normal"))

    def _get_vid_pid_axis(self, show_errors=True):
        """Devuelve (vid, pid, axis_index) o (None, None, None) si falta algo."""
        if not WINREG_OK:
            if show_errors:
                messagebox.showerror("No disponible", "Esta función solo funciona en Windows.")
            return None, None, None
        js = getattr(self.app, "joystick", None)
        if js is None:
            if show_errors:
                messagebox.showerror("Sin dispositivo",
                    "No hay ningún joystick/pedalera conectado ahora mismo.")
            return None, None, None
        try:
            guid = js.get_guid()
        except Exception:
            guid = None
        vid, pid = _guid_to_vid_pid(guid) if guid else (None, None)
        if vid is None or pid is None:
            if show_errors:
                messagebox.showerror("No se pudo identificar el dispositivo",
                    "No pude leer el VID/PID de la pedalera automáticamente.")
            return None, None, None
        try:
            axis_index = int(self.var_di_axis.get())
        except ValueError:
            if show_errors:
                messagebox.showerror("Eje inválido", "El campo 'Eje DirectInput' debe ser un número.")
            return None, None, None
        return vid, pid, axis_index

    def _refrescar_estado_windows(self):
        """Lee lo que hay HOY guardado en el registro para este eje y lo
        muestra, para que no haya dudas de si se aplicó o no. También lo
        cachea para poder simular la barra 'como lo ve Windows'."""
        vid, pid, axis_index = self._get_vid_pid_axis(show_errors=False)
        if vid is None:
            self.lbl_win_status.configure(text="Registro Windows: (sin dispositivo/eje válido)")
            self._win_cal = None
        else:
            current = read_windows_calibration(vid, pid, axis_index)
            self._win_cal = current
            if current is None:
                self.lbl_win_status.configure(
                    text=f"Registro Windows (eje #{axis_index}): sin calibración guardada")
            else:
                lo, ce, hi = current
                self.lbl_win_status.configure(
                    text=f"Registro Windows (eje #{axis_index}): MIN={lo}  CENTRO={ce}  MAX={hi}")
        self.after(2000, self._refrescar_estado_windows)

    def _windows_mapped(self, raw):
        """Simula qué valor (0..1) le entregaría DirectInput a un juego,
        usando la calibración que HOY está guardada en el registro de
        Windows (no la que estás editando en la app)."""
        if not self._win_cal:
            return 0.0
        lo, ce, hi = self._win_cal
        if ce == lo:
            span = hi - lo
            t = (raw - lo) / span if span else 0.0
            return max(0.0, min(1.0, t))
        if raw <= ce:
            span = ce - lo
            t = (raw - lo) / span if span else 0.0
            do = -32768 + t * 32768
        else:
            span = hi - ce
            t = (raw - ce) / span if span else 0.0
            do = t * 32767
        return max(0.0, min(1.0, (do + 32768) / 65535))

    def _aplicar_calibracion_windows(self):
        """Escribe MIN/MAX/CENTRO de este pedal en el registro de Windows,
        para que quede fijo en DirectInput aunque se cierre la app.
        Solo MIN/MAX — la curva no se puede llevar al sistema, eso sigue
        viviendo solo en esta app. El centro se fija igual al MIN (comportamiento
        estándar para un pedal, que solo viaja en un sentido)."""
        vid, pid, axis_index = self._get_vid_pid_axis(show_errors=False)
        if vid is None:
            self.lbl_win_status.configure(text="❌ No se pudo aplicar: sin dispositivo conectado")
            return

        try:
            raw_min = int(self.var_min.get())
            raw_max = int(self.var_max.get())
            raw_center = raw_min
        except ValueError:
            self.lbl_win_status.configure(text="❌ No se pudo aplicar: MIN/MAX inválidos")
            return

        backup_windows_calibration(vid, pid, axis_index, self.label)
        try:
            write_windows_calibration(vid, pid, axis_index, raw_min, raw_center, raw_max)
        except Exception:
            self.lbl_win_status.configure(text="❌ No se pudo escribir en el registro")
            return

        self.btn_aplicar.configure(state="disabled")
        self._refrescar_estado_windows()

    def set_enabled(self, enabled: bool):
        """Atenúa o activa el panel según disponibilidad del eje."""
        self._enabled = enabled
        col_label = self.color if enabled else TEXT_DIM
        col_bar   = self.color if enabled else TEXT_DIM
        # busco el label del titulo, es el primero que aparece
        for widget in self.winfo_children():
            if isinstance(widget, ctk.CTkLabel):
                widget.configure(text_color=col_label)
                break
        self.bar_win.color = col_bar
        if not enabled:
            self.bar.update_values(0, 0.0)
            self.bar_win.update_values(0, 0.0)
            # le aviso al canvas que muestre el cartel de sin eje
            self.curve.set_disabled(True)
        else:
            self.curve.set_disabled(False)
        self._redraw_bar()

    def _redraw_bar(self):
        self.bar_win._redraw()

    def update_display(self, raw_value):
        raw_value = self._raw_corrected(raw_value)
        try:
            mn   = int(self.var_min.get())
            mx   = int(self.var_max.get())
            dz_l = int(self.var_dz_low.get()  or 0)
            dz_h = int(self.var_dz_high.get() or 0)
        except ValueError:
            mn, mx, dz_l, dz_h = 0, 65535, 0, 0
        cp = self.curve.get_points() if self.curve_var.get() == "Personalizada" else None
        if raw_value < mn + dz_l:
            out = 0.0
        elif raw_value > mx - dz_h:
            out = 1.0
        else:
            out = apply_curve(raw_value, self.curve_var.get(), mn + dz_l, mx - dz_h, cp)
        self.bar.update_values(raw_value, out)
        self.bar_win.update_values(raw_value, self._windows_mapped(raw_value))
        self.curve.set_live(out)

    def get_config(self):
        return {
            "min":            int(self.var_min.get()      or 0),
            "max":            int(self.var_max.get()      or 65535),
            "curve":          self.curve_var.get(),
            "deadzone_low":   int(self.var_dz_low.get()  or 0),
            "deadzone_high":  int(self.var_dz_high.get() or 0),
            "control_points": self.curve.get_points(),
            "invert":         bool(self.var_invert.get()),
        }

    def load_config(self, cfg):
        self.var_min.set(str(cfg.get("min", 0)))
        self.var_max.set(str(cfg.get("max", 65535)))
        self.curve_var.set(cfg.get("curve", "Lineal"))
        self.var_dz_low.set(str(cfg.get("deadzone_low", 0)))
        self.var_dz_high.set(str(cfg.get("deadzone_high", 0)))
        self.var_invert.set(bool(cfg.get("invert", False)))
        if "control_points" in cfg:
            self.curve.set_points(cfg["control_points"])
        self.curve.set_curve(self.curve_var.get())


class VRCalibrador(ctk.CTk):

    def __init__(self):
        super().__init__()
        self.title("VR-Simulacion - Calibrador")
        self.geometry("1100x680")
        self.configure(fg_color=BG)
        self.resizable(True, True)

        pygame.init()
        pygame.joystick.init()

        self.joystick  = None
        self.raw_vals  = {p["key"]: 0 for p in PEDALES}
        self._running  = True

        self._build_ui()
        _set_window_icon(self)
        self._connect_joystick()
        self._start_poll()
        self.protocol("WM_DELETE_WINDOW", self._on_close)

    def _build_ui(self):
        # la barra de arriba
        header = ctk.CTkFrame(self, fg_color=PANEL, height=50, corner_radius=0)
        header.pack(fill="x")
        header.pack_propagate(False)

        # si hay logo lo pongo, sino no pasa nada
        self._header_logo = _build_header_logo()
        if self._header_logo:
            ctk.CTkLabel(header, image=self._header_logo, text="",
                         fg_color="transparent").pack(side="left", padx=(8,4), pady=4)
        ctk.CTkLabel(header, text="VR-SIMULACION",
                     font=("Courier New", 16, "bold"),
                     text_color=ACCENT).pack(side="left", padx=(0,0), pady=(6,0))
        ctk.CTkLabel(header, text="CALIBRADOR",
                     font=("Courier New", 9),
                     text_color=TEXT_DIM).pack(side="left", padx=(4,14), pady=(18,0))

        self.status_label = ctk.CTkLabel(header, text="● Sin joystick",
                                          font=FONT_MONO, text_color=ACCENT2)
        self.status_label.pack(side="left", padx=6)

        for txt, cmd in [("Conectar",      self._connect_joystick),
                         ("Guardar perfil", self._save_profile),
                         ("Cargar perfil",  self._load_profile)]:
            ctk.CTkButton(header, text=txt, width=110, height=30,
                           fg_color=BORDER, hover_color="#2a2f3d",
                           text_color=TEXT, font=("Segoe UI", 10),
                           command=cmd).pack(side="right", padx=4, pady=8)

        # combo para elegir el joystick
        js_row = ctk.CTkFrame(self, fg_color="transparent")
        js_row.pack(fill="x", padx=14, pady=(7,0))
        ctk.CTkLabel(js_row, text="Dispositivo:", font=FONT_MONO,
                     text_color=TEXT_DIM).pack(side="left")
        self.device_var  = ctk.StringVar(value="— ninguno —")
        self.device_menu = ctk.CTkOptionMenu(js_row, values=["— ninguno —"],
                                              variable=self.device_var,
                                              fg_color=BORDER, button_color="#2a2f3d",
                                              dropdown_fg_color=PANEL,
                                              font=FONT_UI, width=300,
                                              command=self._select_device)
        self.device_menu.pack(side="left", padx=8)

        # los 3 paneles de pedales, uno al lado del otro
        axes = ctk.CTkFrame(self, fg_color="transparent")
        axes.pack(fill="both", expand=True, padx=14, pady=8)
        axes.columnconfigure(0, weight=1)
        axes.columnconfigure(1, weight=1)
        axes.columnconfigure(2, weight=1)

        self.panels = {}
        for i, p in enumerate(PEDALES):
            panel = AxisPanel(axes, p["label"], p["color"], p["key"], self)
            panel.grid(row=0, column=i, sticky="nsew", padx=4)
            self.panels[p["key"]] = panel

        # la barrita de abajo con la version
        footer = ctk.CTkFrame(self, fg_color=PANEL, height=28, corner_radius=0)
        footer.pack(fill="x", side="bottom")
        footer.pack_propagate(False)
        ctk.CTkLabel(footer, text="VR-Simulacion |  Calibrador v1.8",
                     font=("Courier New", 9), text_color=TEXT_DIM).pack(side="right", padx=12)

    def _connect_joystick(self):
        pygame.joystick.quit()
        pygame.joystick.init()
        devices = [pygame.joystick.Joystick(i).get_name()
                   for i in range(pygame.joystick.get_count())]
        if not devices:
            self.device_menu.configure(values=["— ninguno —"])
            self.device_var.set("— ninguno —")
            self.status_label.configure(text="● Sin joystick", text_color=ACCENT2)
            self.joystick = None
            return
        self.device_menu.configure(values=devices)
        self.device_var.set(devices[0])
        self._select_device(devices[0])

    def _select_device(self, name):
        for i in range(pygame.joystick.get_count()):
            js = pygame.joystick.Joystick(i)
            if js.get_name() == name:
                self.joystick = js
                self.joystick.init()
                n_axes = js.get_numaxes()
                self.status_label.configure(
                    text=f"● {name[:35]}  |  {n_axes} ejes",
                    text_color=ACCENT3)
                # si el volante no tiene 3er eje, el embrague no sirve de nada
                embrague_panel = self.panels.get("embrague")
                if embrague_panel:
                    tiene_embrague = n_axes >= 3
                    embrague_panel.set_enabled(tiene_embrague)
                return
        self.joystick = None

    def get_raw(self, axis_key):
        return self.raw_vals.get(axis_key, 0)

    def _start_poll(self):
        threading.Thread(target=self._poll_loop, daemon=True).start()
        self._schedule_ui()

    def _poll_loop(self):
        while self._running:
            pygame.event.pump()
            if self.joystick:
                try:
                    n = self.joystick.get_numaxes()
                    for p in PEDALES:
                        ax = p["axis"]
                        if ax < n:
                            v = self.joystick.get_axis(ax)
                            self.raw_vals[p["key"]] = int((v + 1) / 2 * 65535)
                except Exception:
                    pass
            time.sleep(0.016)

    def _schedule_ui(self):
        if self._running:
            for p in PEDALES:
                self.panels[p["key"]].update_display(self.raw_vals[p["key"]])
            self.after(16, self._schedule_ui)

    def _save_profile(self):
        path = filedialog.asksaveasfilename(
            defaultextension=".json",
            filetypes=[("VR-Simulacion Profile", "*.json")],
            title="Guardar perfil")
        if not path:
            return
        profile = {p["key"]: self.panels[p["key"]].get_config() for p in PEDALES}
        with open(path, "w") as f:
            json.dump(profile, f, indent=2)
        messagebox.showinfo("VR-Simulacion", f"Perfil guardado:\n{path}")

    def _load_profile(self):
        path = filedialog.askopenfilename(
            filetypes=[("VR-Simulacion Profile", "*.json")],
            title="Cargar perfil")
        if not path:
            return
        with open(path) as f:
            profile = json.load(f)
        for p in PEDALES:
            if p["key"] in profile:
                self.panels[p["key"]].load_config(profile[p["key"]])

    def _on_close(self):
        self._running = False
        pygame.quit()
        self.destroy()


if __name__ == "__main__":
    app = VRCalibrador()
    app.mainloop()
